import{d as e,l,c as a,j as n,o as r}from"./DcGsER3z.js";const s={class:"min-h-screen pt-32 pb-20 bg-white"},k=e({__name:"gizlilik-politikasi",setup(t){return l({title:"Gizlilik Politikası ve KVKK | Vize Acentası",description:"Vize Acentası kişisel verilerinizin korunmasına yönelik aydınlatma metni ve yasal bildiriler."}),(o,i)=>(r(),a("main",s,[...i[0]||(i[0]=[n('<div class="container mx-auto px-4 max-w-4xl prose prose-lg prose-blue"><h1 class="text-4xl font-black text-[#0f172a] mb-8">Gizlilik Politikası ve KVKK Aydınlatma Metni</h1><p>Son Güncelleme: 1 Ocak 2026</p><h3>1. Veri Sorumlusunun Kimliği</h3><p>Vize Acentası olarak kişisel verilerinizin güvenliğine en üst düzeyde önem veriyoruz. 6698 sayılı Kişisel Verilerin Korunması Kanunu (&quot;KVKK&quot;) uyarınca hazırlanan bu metinle sizleri bilgilendiriyoruz.</p><h3>2. İşlenen Kişisel Verileriniz</h3><p>Vize başvuru işlemlerinizin konsolosluklar nezdinde yürütülebilmesi amacıyla; kimlik, pasaport, finansal dökümler, biyometrik fotoğraflar, iletişim ve mesleki verileriniz işlenmektedir.</p><h3>3. Kişisel Verilerinizin Aktarımı</h3><p>Verileriniz <strong>yalnızca</strong> ilgili ülke başkonsoloslukları, yetkili aracı kurumlar (VFS Global, iDATA, Kosmos vb.) ve sigorta acenteleri ile vize işlem zorunlulukları ölçüsünde paylaşılmaktadır. 3. party reklam/pazarlama kuruluşlarına hiçbir şekilde satılmaz veya aktarılmaz.</p><h3>4. Haklarınız</h3><p>KVKK 11. madde uyarınca verilerinizin silinmesini, düzeltilmesini veya işlenip işlenmediğini öğrenme hakkına sahipsiniz. Taleplerinizi info@vize-acentasi.vercel.app üzerinden bize iletebilirsiniz.</p></div>',1)])]))}});export{k as default};
